 73→		user_id?: string;
 74→		project_path?: string;
 75→		repository?: string;
 76→		limit?: number;
 77→		offset?: number;
 78→		sort_by?: "date" | "duration" | "interactions";
 79→		sort_order?: "asc" | "desc";
 80→	} = {},
 81→): Promise<SessionAnalytics[]> {
 82→	const {
 83→		days = 30,
 84→		user_id,
 85→		project_path,
 86→		repository,
 87→		limit = 50,
 88→		offset = 0,
 89→		sort_by = "date",
