591→/**
592→ * Get detailed session information including conversation content
593→ */
594→export async function getSessionDetail(
595→	orgId: string,
596→	sessionId: string,
597→): Promise<SessionDetail | null> {
598→	const org = escapeString(orgId);
599→	const sid = escapeString(sessionId);
600→
601→	const query = `
602→    SELECT
603→      session_id,
604→      user_id,
605→      formatDateTime(sa.session_date, '%Y-%m-%d %H:%i:%S') as session_date,
606→      formatDateTime(sa.last_interaction_date, '%Y-%m-%d %H:%i:%S') as last_interaction_date,
607→      project_path,
608→      repository,
609→      content,
610→      subagents,
611→      skills,
612→      slash_commands,
613→      git_branch,
614→      git_sha,
615→      total_tokens,
616→      input_tokens,
617→      output_tokens,
618→      success_score,
619→      actual_duration_min as duration_min,
620→      total_interactions,
621→      session_archetype,
622→      model_used
623→    FROM rudel.session_analytics sa
624→    WHERE session_id = '${sid}'
625→      AND organization_id = '${org}'
626→    ORDER BY ingested_at DESC
627→    LIMIT 1
628→  `;
629→
630→	const results = await queryClickhouse<SessionDetail>(query);
631→
632→	const [row] = results;
633→	if (!row) {
634→		return null;
635→	}
636→	return {
637→		...row,
638→		repository: row.repository || null,
639→		git_branch: row.git_branch || null,
640→		git_sha: row.git_sha || null,
641→	};
642→}
