  1→import type { UserMapping as UserMappingBase } from "@rudel/api-routes";
  2→import {
  3→	buildDateFilter,
  4→	escapeString,
  5→	queryClickhouse,
  6→} from "../clickhouse.js";
  7→
  8→export interface UserMapping extends UserMappingBase {
  9→	session_count: number;
 10→}
